126		function fmax(arg1 : FREQ; arg2 : FREQ) return FREQ;						-- Calculates: max(arg1, arg2) for frequencies
127		function bmax(arg1 : BAUD; arg2 : BAUD) return BAUD;						-- Calculates: max(arg1, arg2) for symbols per second
128		function mmax(arg1 : MEMORY; arg2 : MEMORY) return MEMORY;			-- Calculates: max(arg1, arg2) for memory
129	
130		-- min/max/sum as vector aggregation
131		function tmin(vec : T_TIMEVEC)	return time;										-- Calculates: min(vec) for a time vector
132		function fmin(vec : T_FREQVEC)	return FREQ;										-- Calculates: min(vec) for a frequency vector
133		function bmin(vec : T_BAUDVEC)	return BAUD;										-- Calculates: min(vec) for a baud vector
134		function mmin(vec : T_MEMVEC)	return MEMORY;									-- Calculates: min(vec) for a memory vector
135	
136		function tmax(vec : T_TIMEVEC)	return time;										-- Calculates: max(vec) for a time vector
137		function fmax(vec : T_FREQVEC)	return FREQ;										-- Calculates: max(vec) for a frequency vector
138		function bmax(vec : T_BAUDVEC)	return BAUD;										-- Calculates: max(vec) for a baud vector
139		function mmax(vec : T_MEMVEC)	return MEMORY;									-- Calculates: max(vec) for a memory vector
140	
141		function tsum(vec : T_TIMEVEC)	return time;										-- Calculates: sum(vec) for a time vector
142		function fsum(vec : T_FREQVEC)	return FREQ;										-- Calculates: sum(vec) for a frequency vector
143		function bsum(vec : T_BAUDVEC)	return BAUD;										-- Calculates: sum(vec) for a baud vector
144		function msum(vec : T_MEMVEC)	return MEMORY;									-- Calculates: sum(vec) for a memory vector
145	
146		-- convert standard types (NATURAL, REAL) to time (TIME)
147		function fs2Time(t_fs : integer)		return time;
148		function ps2Time(t_ps : integer)		return time;
149		function ns2Time(t_ns : integer)		return time;
150		function us2Time(t_us : integer)		return time;
151		function ms2Time(t_ms : integer)		return time;
152		function sec2Time(t_sec : integer)	return time;
153	
154		function fs2Time(t_fs : REAL)				return time;
155		function ps2Time(t_ps : REAL)				return time;
156		function ns2Time(t_ns : REAL)				return time;
157		function us2Time(t_us : REAL)				return time;
158		function ms2Time(t_ms : REAL)				return time;
159		function sec2Time(t_sec : REAL)			return time;
160	
161		-- convert standard types (NATURAL, REAL) to period (TIME)
162		function Hz2Time(f_Hz : natural)		return time;
163		function kHz2Time(f_kHz : natural)	return time;
164		function MHz2Time(f_MHz : natural)	return time;
165		function GHz2Time(f_GHz : natural)	return time;
166	
167		function Hz2Time(f_Hz : REAL)				return time;
168		function kHz2Time(f_kHz : REAL) 		return time;
169		function MHz2Time(f_MHz : REAL) 		return time;
170		function GHz2Time(f_GHz : REAL) 		return time;
171	
172		-- convert standard types (NATURAL, REAL) to frequency (FREQ)
173		function Hz2Freq(f_Hz : natural)		return FREQ;
174		function kHz2Freq(f_kHz : natural)	return FREQ;
175		function MHz2Freq(f_MHz : natural)	return FREQ;
176		function GHz2Freq(f_GHz : natural)	return FREQ;
177	
178		function Hz2Freq(f_Hz : REAL)				return FREQ;
179		function kHz2Freq(f_kHz : REAL)			return FREQ;
180		function MHz2Freq(f_MHz : REAL)			return FREQ;
181		function GHz2Freq(f_GHz : REAL)			return FREQ;
182	
183		-- convert physical types to standard type (REAL)
184		function to_real(t : time;			scale : time)		return REAL;
185		function to_real(f : FREQ;			scale : FREQ)		return REAL;
186		function to_real(br : BAUD;			scale : BAUD)		return REAL;
187		function to_real(mem : MEMORY;	scale : MEMORY)	return REAL;
188	
189		-- convert physical types to standard type (INTEGER)
190		function to_int(t : time;			scale : time;		RoundingStyle : T_ROUNDING_STYLE := ROUND_TO_NEAREST)	return integer;
191		function to_int(f : FREQ;			scale : FREQ;		RoundingStyle : T_ROUNDING_STYLE := ROUND_TO_NEAREST)	return integer;
192		function to_int(br : BAUD;		scale : BAUD;		RoundingStyle : T_ROUNDING_STYLE := ROUND_TO_NEAREST)	return integer;
193		function to_int(mem : MEMORY;	scale : MEMORY;	RoundingStyle : T_ROUNDING_STYLE := ROUND_UP)					return integer;
194	
195		-- calculate needed counter cycles to achieve a given 1. timing/delay and 2. frequency/period
196		function TimingToCycles(Timing : time; Clock_Period			: time; RoundingStyle : T_ROUNDING_STYLE := ROUND_UP) return natural;
197		function TimingToCycles(Timing : time; Clock_Frequency	: FREQ; RoundingStyle : T_ROUNDING_STYLE := ROUND_UP) return natural;
198	
199		function CyclesToDelay(Cycles : natural; Clock_Period			: time) return time;
200		function CyclesToDelay(Cycles : natural; Clock_Frequency	: FREQ) return time;
201	
202		-- convert and format physical types to STRING
203		function to_string(t : time; precision : natural)			return string;
204		function to_string(f : FREQ; precision : natural)			return string;
205		function to_string(br : BAUD; precision : natural)		return string;
206		function to_string(mem : MEMORY; precision : natural)	return string;
207	end package;
208	
209	
210	package body physical is
211	
212		-- WORKAROUND: for simulators with a "Minimal Time Resolution" > 1 fs
213		--	Version:	all
214		--	Vendors:	all
215		--	Issue:
216		--		Some simulators use a lower minimal time resolution (MTR) than the VHDL
217		--		standard (LRM) defines (1 fs). Usually, the MTR is set to 1 ps or 1 ns.
218		--		Most simulators allow the user to specify a higher MTR -> check the
219		--		simulator documentation.
220		--	Solution:
221		--		The currently set MTR can be calculated in VHDL. Using the correct MTR
222		--		can prevent cleared intermediate values and division by zero errors.
223		--	Examples:
224		--		Mentor Graphics QuestaSim/ModelSim (vSim): default MTR = ? ??
225		--		Xilinx ISE Simulator (iSim):               default MTR = 1 ps
226		--		Xilinx Vivado Simulator (xSim):            default MTR = 1 ps
227		function MinimalTimeResolutionInSimulation return time is
228		begin
229			if		(1 fs > 0 sec) then	return 1 fs;
230			elsif	(1 ps > 0 sec) then	return 1 ps;
231			elsif	(1 ns > 0 sec) then	return 1 ns;
232			elsif	(1 us > 0 sec) then	return 1 us;
233			elsif	(1 ms > 0 sec) then	return 1 ms;
234			else											return 1 sec;
235			end if;
236		end function;
237	
238		-- real division for physical types
239		-- ===========================================================================
240		function div(a : time; b : time) return REAL is
241			constant MTRIS	: time		:= MinimalTimeResolutionInSimulation;
242			variable a_real : real;
243			variable b_real : real;
244		begin
245			-- WORKAROUND: for Altera Quartus
246			--	Version:	all
247			--	Issue:
248			--		Results of TIME arithmetic must be in 32-bit integer range, because
249			--		the internally used 64-bit integer for type TIME can not be
250			--		represented in VHDL.
251			--	Solution:
252			--		Pre- and post-scale all values to stay in the integer range.
253		  if    a < 1 us  then
254				a_real  := real(a / MTRIS);
255			elsif a < 1 ms  then
256				a_real  := real(a / (1000 * MTRIS)) * 1000.0;
257			elsif a < 1 sec then
258				a_real  := real(a / (1000000 * MTRIS)) * 1000000.0;
259			else
260				a_real  := real(a / (1000000000 * MTRIS)) * 1000000000.0;
261			end if;
262	
263		  if    b < 1 us  then
264				b_real  := real(b / MTRIS);
265			elsif b < 1 ms  then
266				b_real  := real(b / (1000 * MTRIS)) * 1000.0;
267			elsif b < 1 sec then
268				b_real  := real(b / (1000000 * MTRIS)) * 1000000.0;
269			else
270				b_real  := real(b / (1000000000 * MTRIS)) * 1000000000.0;
271			end if;
272	
273			return a_real / b_real;
274		end function;
275	
276		function div(a : FREQ; b : FREQ) return REAL is
277		begin
278			return real(a / 1 Hz) / real(b / 1 Hz);
279		end function;
280	
281		function div(a : BAUD; b : BAUD) return REAL is
282		begin
283			return real(a / 1 Bd) / real(b / 1 Bd);
284		end function;
285	
286		function div(a : MEMORY; b : MEMORY) return REAL is
287		begin
288			return real(a / 1 Byte) / real(b / 1 Byte);
289		end function;
290	
291		-- conversion functions
292		-- ===========================================================================
293		function to_time(f : FREQ) return time is
294			variable res : time;
295		begin
296			res := div(1000 MHz, f) * 1 ns;
297			if POC_VERBOSE then
298				report "to_time: f= " & to_string(f, 3) & "  return " & to_string(res, 3) severity note;
299			end if;
300			return res;
301		end function;
302	
303		function to_freq(p : time) return FREQ is
304			variable res : FREQ;
305		begin
306			if (p <= 1 sec) then res := div(1 sec, p) * 1  Hz;
307			else report "to_freq: input period exceeds output frequency scale." severity failure;
308			end if;
309			if POC_VERBOSE then
310				report "to_freq: p= " & to_string(p, 3) & "  return " & to_string(res, 3) severity note;
311			end if;
312			return res;
313		end function;
314	
315		function to_freq(br : BAUD) return FREQ is
316			variable res : FREQ;
317		begin
318			res := (br / 1 Bd)	* 1  Hz;
319			if POC_VERBOSE then
320				report "to_freq: br= " & to_string(br, 3) & "  return " & to_string(res, 3) severity note;
321			end if;
322			return res;
323		end function;
324	
325		function to_baud(str : string) return BAUD is
326			variable pos		: integer;
327			variable int		: natural;
328			variable base		: positive;
329			variable frac		: natural;
330			variable digits	: natural;
331		begin
332			pos			:= str'low;
333			int			:= 0;
334			frac		:= 0;
335			digits	:= 0;
336			-- read integer part
337			for i in pos to str'high loop
338				if chr_isDigit(str(i)) then		int := int * 10 + to_digit_dec(str(i));
339				elsif (str(i) = '.') then								pos	:= -i;	exit;
340				elsif (str(i) = ' ') then								pos	:= i;		exit;
341				else																		pos := 0;		exit;
342				end if;
343			end loop;
344			-- read fractional part
345			if ((pos < 0) and (-pos < str'high)) then
346				for i in -pos+1 to str'high loop
347					if ((frac = 0) and (str(i) = '0')) then	next;
348					elsif chr_isDigit(str(i)) then	frac	:= frac * 10 + to_digit_dec(str(i));
349					elsif (str(i) = ' ') then								digits	:= i + pos - 1;	pos	:= i;	exit;
350					else																														pos	:= 0;	exit;
351					end if;
352				end loop;
353			end if;
354			-- abort if format is unknown
355			if pos = 0 then report "to_baud: Unknown format" severity FAILURE;	end if;
356			-- parse unit
357			pos := pos + 1;
358			if ((pos + 1 = str'high) and (str(pos to pos + 1) = "Bd")) then
359																			return int * 1 Bd;
360			elsif (pos + 2 = str'high) then
361				if (str(pos to pos + 2) = "kBd") then
362					if frac = 0 then					return (int * 1 kBd);
363					elsif (digits <= 3) then		return (int * 1 kBd) + (frac * 10**(3 - digits) * 1 Bd);
364					else												return (int * 1 kBd) + (frac / 10**(digits - 3) * 100 Bd);
365					end if;
366				elsif (str(pos to pos + 2) = "MBd") then
367					if frac = 0 then					return (int * 1 kBd);
368					elsif (digits <= 3) then		return (int * 1 MBd) + (frac * 10**(3 - digits) * 1 kBd);
369					elsif (digits <= 6) then		return (int * 1 MBd) + (frac * 10**(6 - digits) * 1 Bd);
370					else												return (int * 1 MBd) + (frac / 10**(digits - 6) * 100000 Bd);
371					end if;
372				elsif (str(pos to pos + 2) = "GBd") then
373					if frac = 0 then					return (int * 1 kBd);
374					elsif (digits <= 3) then		return (int * 1 GBd) + (frac * 10**(3 - digits) * 1 MBd);
375					elsif (digits <= 6) then		return (int * 1 GBd) + (frac * 10**(6 - digits) * 1 kBd);
376					elsif (digits <= 9) then		return (int * 1 GBd) + (frac * 10**(9 - digits) * 1 Bd);
377					else												return (int * 1 GBd) + (frac / 10**(digits - 9) * 100000000 Bd);
378					end if;
379				else
380					report "to_baud: Unknown unit." severity FAILURE;
381				end if;
382			else
383				report "to_baud: Unknown format" severity FAILURE;
384			end if;
385			return 0 Bd;
386		end function;
