788		-- convert physical types to standard type (REAL)
789		-- ===========================================================================
790		function to_real(t : time; scale : time) return REAL is
791		begin
792			if		(scale = 1	fs) then	return div(t, 1	 fs);
793			elsif	(scale = 1	ps) then	return div(t, 1	 ps);
794			elsif	(scale = 1	ns) then	return div(t, 1	 ns);
795			elsif	(scale = 1	us) then	return div(t, 1	 us);
796			elsif	(scale = 1	ms) then	return div(t, 1	 ms);
797			elsif	(scale = 1 sec) then	return div(t, 1 sec);
798			else	report "to_real: scale must have a value of '1 <unit>'" severity failure;
799			return 0.0;
800			end if;
801		end;
