887		-- calculate needed counter cycles to achieve a given 1. timing/delay and 2. frequency/period
888		-- ===========================================================================
889		--	@param Timing					A given timing or delay, which should be achieved
890		--	@param Clock_Period		The period of the circuits clock
891		--	@RoundingStyle				Default = ROUND_UP; other choises: ROUND_UP, ROUND_DOWN, ROUND_TO_NEAREST
892		function TimingToCycles(Timing : time; Clock_Period : time; RoundingStyle : T_ROUNDING_STYLE := ROUND_UP) return natural is
893			variable res_real	: REAL;
894			variable res_nat	: natural;
895			variable res_time	: time;
896			variable res_dev	: REAL;
897		begin
898			res_real := div(Timing, Clock_Period);
899			case RoundingStyle is
900				when ROUND_TO_NEAREST =>	res_nat := natural(round(res_real));
901				when ROUND_UP =>					res_nat := natural(ceil(res_real));
902				when ROUND_DOWN =>				res_nat := natural(floor(res_real));
903				when others =>	report "RoundingStyle '" & T_ROUNDING_STYLE'image(RoundingStyle) & "' not supported." severity failure;
904			end case;
905			res_time	:= CyclesToDelay(res_nat, Clock_Period);
906			res_dev		:= (div(res_time, Timing) - 1.0) * 100.0;
907	
908			if POC_VERBOSE then
909				report "TimingToCycles: " & 	LF &
910							 "  Timing: " &					to_string(Timing, 3) & LF &
911							 "  Clock_Period: " &		to_string(Clock_Period, 3) & LF &
912							 "  RoundingStyle: " &	str_substr(T_ROUNDING_STYLE'image(RoundingStyle), 7) & LF &
913							 "  res_real = " &			str_format(res_real, 3) & LF &
914							 "  => " &							integer'image(res_nat)
915				severity note;
916			end if;
917	
918			if C_PHYSICAL_REPORT_TIMING_DEVIATION then
919				report "TimingToCycles (timing deviation report): " & LF &
920							 "  timing to achieve: " & to_string(Timing, 3) & LF &
921							 "  calculated cycles: " & integer'image(res_nat) & " cy" & LF &
922							 "  resulting timing:  " & to_string(res_time, 3) & LF &
923							 "  deviation:         " & to_string(res_time - Timing, 3) & " (" & str_format(res_dev, 2) & "%)"
924				severity note;
925			end if;
926	
927			return res_nat;
928		end;
929	
930		function TimingToCycles(Timing : time; Clock_Frequency	: FREQ; RoundingStyle : T_ROUNDING_STYLE := ROUND_UP) return natural is
931		begin
932			return TimingToCycles(Timing, to_time(Clock_Frequency), RoundingStyle);
933		end function;
