945		-- convert and format physical types to STRING
946		function to_string(t : time; precision : natural) return string is
947			variable tt     : time;
948			variable unit		: string(1 to 3)	:= (others => C_POC_NUL);
949			variable value	: REAL;
950		begin
951			tt := abs t;
952			if (tt < 1 ps) then
953				unit(1 to 2)	:= "fs";
954				value					:= to_real(tt, 1 fs);
955			elsif (tt < 1 ns) then
956				unit(1 to 2)	:= "ps";
957				value					:= to_real(tt, 1 ps);
958			elsif (tt < 1 us) then
959				unit(1 to 2)	:= "ns";
960				value					:= to_real(tt, 1 ns);
961			elsif (tt < 1 ms) then
962				unit(1 to 2)	:= "us";
963				value					:= to_real(tt, 1 us);
964			elsif (tt < 1 sec) then
965				unit(1 to 2)	:= "ms";
966				value					:= to_real(tt, 1 ms);
967			else
968				unit					:= "sec";
969				value					:= to_real(tt, 1 sec);
970			end if;
971	
972			return ite(t >= 0 fs, str_format(value, precision) & " " & str_trim(unit),
973								      '-' & str_format(value, precision) & " " & str_trim(unit));
974		end function;
975	
976		function to_string(f : FREQ; precision : natural) return string is
977			variable unit		: string(1 to 3)	:= (others => C_POC_NUL);
978			variable value	: REAL;
979		begin
980			if (f < 1 kHz) then
981				unit(1 to 2)	:= "Hz";
982				value					:= to_real(f, 1 Hz);
983			elsif (f < 1 MHz) then
984				unit					:= "kHz";
985				value					:= to_real(f, 1 kHz);
986			elsif (f < 1 GHz) then
987				unit					:= "MHz";
988				value					:= to_real(f, 1 MHz);
989			else
990				unit					:= "GHz";
991				value					:= to_real(f, 1 GHz);
992			end if;
993	
994			return str_format(value, precision) & " " & str_trim(unit);
995		end function;
996	
997		function to_string(br : BAUD; precision : natural) return string is
998			variable unit		: string(1 to 3)	:= (others => C_POC_NUL);
999			variable value	: REAL;
1000		begin
1001			if (br < 1 kBd) then
1002				unit(1 to 2)	:= "Bd";
1003				value					:= to_real(br, 1 Bd);
1004			elsif (br < 1 MBd) then
1005				unit					:= "kBd";
1006				value					:= to_real(br, 1 kBd);
1007			elsif (br < 1 GBd) then
1008				unit					:= "MBd";
1009				value					:= to_real(br, 1 MBd);
1010			else
1011				unit					:= "GBd";
1012				value					:= to_real(br, 1 GBd);
1013			end if;
1014	
1015			return str_format(value, precision) & " " & str_trim(unit);
1016		end function;
1017	
1018		function to_string(mem : MEMORY; precision : natural) return string is
1019			variable unit		: string(1 to 3)	:= (others => C_POC_NUL);
1020			variable value	: REAL;
1021		begin
1022			if (mem < 1 KiB) then
1023				unit(1)				:= 'B';
1024				value					:= to_real(mem, 1 Byte);
1025			elsif (mem < 1 MiB) then
1026				unit					:= "KiB";
1027				value					:= to_real(mem, 1 KiB);
1028			elsif (mem < 1 GiB) then
1029				unit					:= "MiB";
1030				value					:= to_real(mem, 1 MiB);
1031			else
1032				unit					:= "GiB";
1033				value					:= to_real(mem, 1 GiB);
1034			end if;
1035	
1036			return str_format(value, precision) & " " & str_trim(unit);
1037		end function;
1038	
1039	end package body;
1040

