282		function raw_format_slv_bin(slv : std_logic_vector) return string is
283			variable Value				: std_logic_vector(slv'length - 1 downto 0);
284			variable Result				: string(1 to slv'length);
285			variable j						: natural;
286		begin
287			-- convert input slv to a downto ranged vector and normalize range to slv'low = 0
288			Value := movez(ite(slv'ascending, descend(slv), slv));
289			-- convert each bit to a character
290			j := 0;
291			for i in Result'reverse_range loop
292				Result(i)	:= to_char(Value(j));
293				j					:= j + 1;
294			end loop;
295			return Result;
296		end function;
297	
298		function raw_format_slv_oct(slv : std_logic_vector) return string is
299			variable Value				: std_logic_vector(slv'length - 1 downto 0);
300			variable Digit				: std_logic_vector(2 downto 0);
301			variable Result				: string(1 to div_ceil(slv'length, 3));
302			variable j						: natural;
303		begin
304			-- convert input slv to a downto ranged vector; normalize range to slv'low = 0 and resize it to a multiple of 3
305			Value := resize(movez(ite(slv'ascending, descend(slv), slv)), (Result'length * 3));
306			-- convert 3 bit to a character
307			j := 0;
308			for i in Result'reverse_range loop
309				Digit			:= Value((j * 3) + 2 downto (j * 3));
310				Result(i)	:= to_HexChar(unsigned(Digit));
311				j					:= j + 1;
312			end loop;
313	
314			return Result;
315		end function;
316	
317		function raw_format_slv_dec(slv : std_logic_vector) return string is
318			variable Value				: std_logic_vector(slv'length - 1 downto 0);
319			variable Result				: string(1 to div_ceil(slv'length, 3));
320	
321			subtype	TT_BCD				is integer range 0 to 31;
322			type		TT_BCD_VECTOR	is array(natural range <>) of TT_BCD;
323	
324			variable Temp		: TT_BCD_VECTOR(div_ceil(slv'length, 3) - 1 downto 0);
325			variable Carry	: T_UINT_8;
326	
327			variable Pos		: natural;
328		begin
329			Temp	:= (others => 0);
330			Pos		:= 0;
331			-- convert input slv to a downto ranged vector
332			Value := ite(slv'ascending, descend(slv), slv);
333	
334			for i in Value'range loop
335				Carry		:= to_int(Value(i));
336				for j in Temp'reverse_range loop
337					Temp(j)	:= Temp(j) * 2 + Carry;
338					Carry		:=						to_int(Temp(j) > 9);
339					Temp(j)	:= Temp(j) - to_int((Temp(j) > 9), 0, 10);
340				end loop;
341			end loop;
342	
343			for i in Result'range loop
344				Result(i)		:= to_HexChar(Temp(Temp'high - i + 1));
345				if ((Result(i) /= '0') and (Pos = 0)) then
346					Pos	:= i;
347				end if;
348			end loop;
349			-- trim leading zeros, except the last
350			return Result(imin(Pos, Result'high) to Result'high);
351		end function;
352	
353		function raw_format_slv_hex(slv : std_logic_vector) return string is
354			variable Value				: std_logic_vector(4*div_ceil(slv'length, 4) - 1 downto 0);
355			variable Digit				: std_logic_vector(3 downto 0);
356			variable Result				: string(1 to div_ceil(slv'length, 4));
357			variable j						: natural;
358		begin
359			Value := resize(slv, Value'length);
360			j			:= 0;
361			for i in Result'reverse_range loop
362				Digit			:= Value((j * 4) + 3 downto (j * 4));
363				Result(i)	:= to_HexChar(unsigned(Digit));
364				j					:= j + 1;
365			end loop;
366			return Result;
367		end function;
