391		function str_format(Value : REAL; precision : natural := 3) return string is
392			constant s				: REAL		:= sign(Value);
393			constant val			: REAL		:= Value * s;
394			constant int			: integer	:= integer(floor(val));
395			constant frac			: integer	:= integer(round((val - real(int)) * 10.0**precision));
396			constant overflow : boolean := frac >= 10**precision;
397			constant int2     : integer := ite(overflow, int+1, int);
398			constant frac2    : integer := ite(overflow, frac-10**precision, frac);
399			constant frac_str	: string	:= integer'image(frac2);
400			constant res			: string	:= integer'image(int2) & "." & (2 to (precision - frac_str'length + 1) => '0') & frac_str;
401		begin
402			return ite ((s < 0.0), "-" & res, res);
403		end function;
