412		-- convert an integer Value to a STRING using an arbitrary base
413		function to_string(Value : integer; base : positive := 10) return string is
414			constant absValue		: natural								:= abs Value;
415			constant len		 		: positive							:= log10ceilnz(absValue);
416			variable power			: positive;
417			variable Result			: string(1 to len);
418		begin
419			power		:= 1;
420	
421			if base = 10 then
422				return integer'image(Value);
423			else
424				for i in len downto 1 loop
425					Result(i)		:= to_HexChar(absValue / power mod base);
426					power				:= power * base;
427				end loop;
428	
429				if Value < 0 then
430					return '-' & Result;
431				else
432					return Result;
433				end if;
434			end if;
435		end function;
