437		-- QUESTION: rename to slv_format(..) ?
438		function to_string(slv : std_logic_vector; format : character; Length : natural := 0; fill : character := '0') return string is
439			constant int					: integer				:= ite((slv'length <= 31), to_integer(unsigned(resize(slv, 31))), 0);
440			constant str					: string				:= integer'image(int);
441			constant bin_len			: positive			:= slv'length;
442			constant dec_len			: positive			:= str'length;--log10ceilnz(int);
443			constant hex_len			: positive			:= ite(((bin_len mod 4) = 0), (bin_len / 4), (bin_len / 4) + 1);
444			constant len					: natural				:= ite((format = 'b'), bin_len,
445																							 ite((format = 'd'), dec_len,
446																							 ite((format = 'h'), hex_len, 0)));
447			variable j						: natural;
448			variable Result				: string(1 to ite((Length = 0), len, imax(len, Length)));
449		begin
450			j				:= 0;
451			Result	:= (others => fill);
452	
453			if (format = 'b') then
454				for i in Result'reverse_range loop
455					Result(i)		:= to_char(slv(j));
456					j						:= j + 1;
457				end loop;
458			elsif (format = 'd') then
459				-- TODO: enable big integer conversion
460	--			if (slv'length < 32) then
461	--				return INTEGER'image(int);
462	--			else
463	--				return raw_format_slv_dec(slv);
464	--			end if;
465				Result(Result'length - str'length + 1 to Result'high)	:= str;
466			elsif (format = 'h') then
467				for i in Result'reverse_range loop
468					Result(i)		:= to_HexChar(unsigned(slv((j * 4) + 3 downto (j * 4))));
469					j						:= j + 1;
470				end loop;
471			else
472				report "Unknown format character: " & format & "." severity FAILURE;
473			end if;
474	
475			return Result;
476		end function;
