509		-- convert a binary digit given as CHARACTER to a digit returned as NATURAL; return -1 on error
510		function to_digit_bin(chr : character) return T_DIGIT_BIN is
511		begin
512			case chr is
513				when '0' =>			return 0;
514				when '1' =>			return 1;
515				when others =>	return -1;
516			end case;
517		end function;
