519		-- convert an octal digit given as CHARACTER to a digit returned as NATURAL; return -1 on error
520		function to_digit_oct(chr : character) return T_DIGIT_OCT is
521			variable dec : integer;
522		begin
523			dec := to_digit_dec(chr);
524			return ite((dec < 8), dec, -1);
525		end function;
