527		-- convert a adecimal digit given as CHARACTER to a digit returned as NATURAL; return -1 on error
528		function to_digit_dec(chr : character) return T_DIGIT_DEC is
529		begin
530			if chr_isDigit(chr) then
531				return character'pos(chr) - CHARACTER'pos('0');
532			else
533				return -1;
534			end if;
535		end function;
536	
537		-- convert a hexadecimal digit given as CHARACTER to a digit returned as NATURAL; return -1 on error
538		function to_digit_hex(chr : character) return T_DIGIT_HEX is
539		begin
540			if chr_isDigit(chr) then						return character'pos(chr) - CHARACTER'pos('0');
541			elsif chr_isLowerHexDigit(chr) then	return character'pos(chr) - CHARACTER'pos('a') + 10;
542			elsif chr_isUpperHexDigit(chr) then	return character'pos(chr) - CHARACTER'pos('A') + 10;
543			else																return -1;
544			end if;
545		end function;
546	
547		-- convert a digit given as CHARACTER to a digit returned as NATURAL; return -1 on error
548		function to_digit(chr : character; base : character := 'd') return integer is
549		begin
550			case base is
551				when 'b' =>			return to_digit_bin(chr);
552				when 'o' =>			return to_digit_oct(chr);
553				when 'd' =>			return to_digit_dec(chr);
554				when 'h' =>			return to_digit_hex(chr);
555				when others =>	report "Unknown base character: " & base & "." severity FAILURE;
556												return -1;
557			end case;
558		end function;
