560		-- to_natural*
561		-- ===========================================================================
562		-- convert a binary number given as STRING to a NATURAL; return -1 on error
563		function to_natural_bin(str : string) return integer is
564			variable Result			: natural;
565			variable Digit			: integer;
566		begin
567			for i in str'range loop
568				Digit	:= to_digit_bin(str(i));
569				if Digit /= -1 then
570					Result	:= Result * 2 + Digit;
571				else
572					return -1;
573				end if;
574			end loop;
575			return Result;
576		end function;
