578		-- convert an octal number given as STRING to a NATURAL; return -1 on error
579		function to_natural_oct(str : string) return integer is
580			variable Result			: natural;
581			variable Digit			: integer;
582		begin
583			for i in str'range loop
584				Digit	:= to_digit_oct(str(i));
585				if Digit /= -1 then
586					Result	:= Result * 8 + Digit;
587				else
588					return -1;
589				end if;
590			end loop;
591			return Result;
592		end function;
