594		-- convert a decimal number given as STRING to a NATURAL; return -1 on error
595		function to_natural_dec(str : string) return integer is
596			variable Result			: natural;
597			variable Digit			: integer;
598		begin
599			-- WORKAROUND: Xilinx Vivado Synth
600			--	Version:	2014.1
601			--	Issue:
602			--		INTEGER'value(...) is not supported by Vivado Synth
603			--	Solution:
604			--		implement a manual conversion using shift and multiply
605			for i in str'range loop
606				Digit	:= to_digit_dec(str(i));
607				if Digit /= -1 then
608					Result	:= Result * 10 + Digit;
609				else
610					return -1;
611				end if;
612			end loop;
613			return Result;	-- INTEGER'value(str);
614		end function;
615	
616		-- convert a hexadecimal number given as STRING to a NATURAL; return -1 on error
617		function to_natural_hex(str : string) return integer is
618			variable Result			: natural;
619			variable Digit			: integer;
620		begin
621			for i in str'range loop
622				Digit	:= to_digit_hex(str(i));
623				if Digit /= -1 then
624					Result	:= Result * 16 + Digit;
625				else
626					return -1;
627				end if;
628			end loop;
629			return Result;
630		end function;
631	
632		-- convert a number given as STRING to a NATURAL; return -1 on error
633		function to_natural(str : string; base : character := 'd') return integer is
634		begin
635			case base is
636				when 'b' =>			return to_natural_bin(str);
637				when 'o' =>			return to_natural_oct(str);
638				when 'd' =>			return to_natural_dec(str);
639				when 'h' =>			return to_natural_hex(str);
640				when others =>	report "Unknown base character: " & base & "." severity FAILURE;
641												return -1;
642			end case;
643		end function;
