665		function resize(str : string; Size : positive; FillChar : character := C_POC_NUL) return string is
666			constant ConstNUL		: string(1 to 1)				:= (others => C_POC_NUL);
667			variable Result			: string(1 to Size);
668		begin
669			Result := (others => FillChar);
670			if (str'length > 0) then
671				-- WORKAROUND: for Altera Quartus-II
672				--	Version:	15.0
673				--	Issue:		array bounds are check regardless of the hierarchy and control flow
674				Result(1 to bound(Size, 1, str'length)) := ite((str'length > 0), str(1 to imin(Size, str'length)), ConstNUL);
675			end if;
676			return Result;
677		end function;
678	
679	--	function resize(str : T_RAWSTRING; size : POSITIVE; FillChar : T_RAWCHAR := x"00") return T_RAWSTRING is
680	--		constant ConstNUL		: T_RAWSTRING(1 to 1)				:= (others => x"00");
681	--		variable Result			: T_RAWSTRING(1 to size);
