693	--			Result(1 to imin(size, imax(1, str'length))) := ifthenelse((str'length > 0), str(1 to imin(size, str'length)), ConstNUL);
694	--		end if;
695	--		return Result;
696	--	end function;
697	
698	
699		-- Character functions
700		-- ===========================================================================
701		-- convert an upper case CHARACTER into a lower case CHARACTER
702		function chr_toLower(chr : character) return character is
703		begin
704			if chr_isUpperAlpha(chr) then
705				return character'val(character'pos(chr) - character'pos('A') + character'pos('a'));
706			else
707				return chr;
708			end if;
709		end function;
710	
711		-- convert a lower case CHARACTER into an upper case CHARACTER
712		function chr_toUpper(chr : character) return character is
713		begin
714			if chr_isLowerAlpha(chr) then
715				return character'val(character'pos(chr) - character'pos('a') + character'pos('A'));
716			else
717				return chr;
718			end if;
719		end function;
720	
721		-- String functions
722		-- ===========================================================================
723		-- count the length of a POC_NUL terminated STRING
724		function str_length(str : string) return natural is
725		begin
726			for i in str'range loop
727				if str(i) = C_POC_NUL then
728					return i - str'low;
729				end if;
730			end loop;
731			return str'length;
732		end function;
733	
734		-- compare two STRINGs for equality
735		-- pre-check the string lengthes to suppress warnings for unqual sized string comparisons.
736		-- QUESTION: overload "=" operator?
737		function str_equal(str1 : string; str2 : string) return boolean is
738		begin
739			if str1'length /= str2'length then
740				return FALSE;
741			else
742				return (str1 = str2);
743			end if;
744		end function;
745	
746		-- compare two POC_NUL terminated STRINGs
747		function str_match(str1 : string; str2 : string) return boolean is
748			constant len	: natural 		:= imin(str1'length, str2'length);
749		begin
750			-- if both strings are empty
751			if ((str1'length = 0 ) and (str2'length = 0)) then		return TRUE;	end if;
752			-- compare char by char
753			for i in str1'low to str1'low + len - 1 loop
754				if (str1(i) /= str2(str2'low + (i - str1'low))) then
755					return FALSE;
756				elsif ((str1(i) = C_POC_NUL) xor (str2(str2'low + (i - str1'low)) = C_POC_NUL)) then
757					return FALSE;
758				elsif ((str1(i) = C_POC_NUL) and (str2(str2'low + (i - str1'low)) = C_POC_NUL)) then
759					return TRUE;
760				end if;
761			end loop;
762			-- check special cases,
763			return (((str1'length = len) and (str2'length = len)) or									-- both strings are fully consumed and equal
764							((str1'length > len) and (str1(str1'low + len) = C_POC_NUL)) or		-- str1 is longer, but str_length equals len
765							((str2'length > len) and (str2(str2'low + len) = C_POC_NUL)));		-- str2 is longer, but str_length equals len
766		end function;
767	
768		-- compare two POC_NUL terminated STRINGs; case insentitve
769		function str_imatch(str1 : string; str2 : string) return boolean is
770		begin
771			return str_match(str_toLower(str1), str_toLower(str2));
772		end function;
773	
774		-- search for chr in a STRING and return the position; return -1 on error
775		function str_pos(str : string; chr : character; start : natural := 0) return integer is
776		begin
777			for i in imax(str'low, start) to str'high loop
778				exit when (str(i) = C_POC_NUL);
779				if str(i) = chr then
780					return i;
781				end if;
782			end loop;
783			return -1;
784		end function;
785	
786		-- search for pattern in a STRING and return the position; return -1 on error
787		-- QUESTION: implement KMP algorithm?
788		function str_pos(str : string; pattern : string; start : natural := 0) return integer is
789		begin
790			for i in imax(str'low, start) to (str'high - pattern'length + 1) loop
791				exit when (str(i) = C_POC_NUL);
792				if (str(i to i + pattern'length - 1) = pattern) then
793					return i;
794				end if;
795			end loop;
796			return -1;
797		end function;
798	
799		-- search for chr in a STRING and return the position; case insentitve; return -1 on error
800		function str_ipos(str : string; chr : character; start : natural := 0) return integer is
801		begin
802			return str_pos(str_toLower(str), chr_toLower(chr));
803		end function;
804	
805		-- search for pattern in a STRING and return the position; case insentitve; return -1 on error
806		function str_ipos(str : string; pattern : string; start : natural := 0) return integer is
807		begin
808			return str_pos(str_toLower(str), str_toLower(pattern));
809		end function;
810	
811	--	function str_pos(str1 : STRING; str2 : STRING) return INTEGER is
812	--		variable PrefixTable	: T_INTVEC(0 to str2'length);
813	--		variable j						: INTEGER;
814	--	begin
815	--		-- construct prefix table for KMP algorithm
816	--		j								:= -1;
817	--		PrefixTable(0)	:= -1;
818	--		for i in str2'range loop
819	--			while ((j >= 0) and str2(j + 1) /= str2(i)) loop
820	--				j		:= PrefixTable(j);
821	--			end loop;
822	--
823	--			j										:= j + 1;
824	--			PrefixTable(i - 1)	:= j + 1;
825	--		end loop;
826	--
827	--		-- search pattern str2 in text str1
828	--		j := 0;
829	--		for i in str1'range loop
830	--			while ((j >= 0) and str1(i) /= str2(j + 1)) loop
831	--				j		:= PrefixTable(j);
832	--			end loop;
833	--
834	--			j := j + 1;
835	--			if ((j + 1) = str2'high) then
836	--				return i - str2'length + 1;
837	--			end if;
838	--		end loop;
839	--
840	--		return -1;
841	--	end function;
842	
843		-- check if chr exists in STRING str
844		function str_find(str : string; chr : character) return boolean is
845		begin
846			return (str_pos(str, chr) > 0);
847		end function;
848	
849		-- check if pattern exists in STRING str
850		function str_find(str : string; pattern : string) return boolean is
851		begin
852			return (str_pos(str, pattern) > 0);
853		end function;
854	
855		-- check if chr exists in STRING str; case insentitve
856		function str_ifind(str : string; chr : character) return boolean is
857		begin
858			return (str_ipos(str, chr) > 0);
859		end function;
860	
861		-- check if pattern exists in STRING str; case insentitve
862		function str_ifind(str : string; pattern : string) return boolean is
863		begin
864			return (str_ipos(str, pattern) > 0);
865		end function;
866	
867		-- replace a pattern in a STRING str by the STRING replace
868		function str_replace(str : string; pattern : string; replace : string) return string is
869			variable pos		: integer;
870		begin
871			pos := str_pos(str, pattern);
872			if pos > 0 then
873				if pos = 1 then
874					return replace & str(pattern'length + 1 to str'length);
875				elsif (pos = str'length - pattern'length + 1) then
876					return str(1 to str'length - pattern'length) & replace;
877				else
878					return str(1 to pos - 1) & replace & str(pos + pattern'length to str'length);
879				end if;
880			else
881				return str;
882			end if;
883		end function;
884	
885		-- return a sub-string of STRING str
886		-- EXAMPLES:
887		--							  123456789ABC
888		-- input string: "Hello World."
889		--	low=1; high=12; length=12
890		--
891		--	str_substr("Hello World.",	0,	0)	=> "Hello World."		- copy all
892		--	str_substr("Hello World.",	7,	0)	=> "World."					- copy from pos 7 to end of string
893		--	str_substr("Hello World.",	7,	5)	=> "World"					- copy from pos 7 for 5 characters
894		--	str_substr("Hello World.",	0, -7)	=> "Hello World."		- copy all until character 8 from right boundary
895		function str_substr(str : string; start : integer := 0; Length : integer := 0) return string is
896			variable StartOfString		: positive;
897			variable EndOfString			: positive;
898		begin
899			if start < 0 then			-- start is negative -> start substring at right string boundary
900				StartOfString		:= str'high + start + 1;
901			elsif start = 0 then	-- start is zero -> start substring at left string boundary
902				StartOfString		:= str'low;
903			else 										-- start is positive -> start substring at left string boundary + offset
904				StartOfString		:= start;
905			end if;
906	
907			if Length < 0 then		-- Length is negative -> end substring at length'th character before right string boundary
908				EndOfString			:= str'high + Length;
909			elsif Length = 0 then	-- Length is zero -> end substring at right string boundary
910				EndOfString			:= str'high;
911			else										-- Length is positive -> end substring at StartOfString + Length
912				EndOfString			:= StartOfString + Length - 1;
913			end if;
914	
915			if (StartOfString < str'low) then			report "StartOfString is out of str's range. (str=" & str & ")"	severity FAILURE;		end if;
916			if (EndOfString < str'high) then			report "EndOfString is out of str's range. (str=" & str & ")"		severity FAILURE;		end if;
917	
918			return str(StartOfString to EndOfString);
919		end function;
920	
921		-- left-trim the STRING str
922		function str_ltrim(str : string; char : character := ' ') return string is
923		begin
924			for i in str'range loop
925				if str(i) /= char then
926					return str(i to str'high);
927				end if;
928			end loop;
929			return "";
930		end function;
931	
932		-- right-trim the STRING str
933		function str_rtrim(str : string; char : character := ' ') return string is
934		begin
935			for i in str'reverse_range loop
936				if str(i) /= char then
937					return str(str'low to i);
938				end if;
939			end loop;
940			return "";
941		end function;
942	
943		-- remove POC_NUL string termination characters
944		function str_trim(str : string) return string is
945		begin
946			return str(str'low to str'low + str_length(str) - 1);
947		end function;
948	
949		-- center-align a STRING str in a FillChar filled STRING of length Length
950		function str_calign(str : string; Length : natural; FillChar : character := ' ') return string is
951			constant Start		: positive	:= (Length - str'length) / 2;
952			variable Result		: string(1 to Length);
953		begin
954			Result		:= (others => FillChar);
955			Result(Start to (Start + str'length))	:= str;
956			return Result;
957		end function;
958	
959		-- left-align a STRING str in a FillChar filled STRING of length Length
960		function str_lalign(str : string; Length : natural; FillChar : character := ' ') return string is
961			variable Result		: string(1 to Length);
962		begin
963			Result		:= (others => FillChar);
964			Result(1 to str'length)	:= str;
965			return Result;
966		end function;
967	
968		-- right-align a STRING str in a FillChar filled STRING of length Length
969		function str_ralign(str : string; Length : natural; FillChar : character := ' ') return string is
970			variable Result		: string(1 to Length);
971		begin
972			Result		:= (others => FillChar);
973			Result((Length - str'length + 1) to Length)	:= str;
974			return Result;
975		end function;
976	
977		-- convert an upper case STRING into a lower case STRING
978		function str_toLower(str : string) return string is
979			variable Result		: string(str'range);
980		begin
981			for i in str'range loop
982				Result(i)	:= chr_toLower(str(i));
983			end loop;
984			return Result;
985		end function;
986	
987		-- convert a lower case STRING into an upper case STRING
988		function str_toUpper(str : string) return string is
989			variable Result		: string(str'range);
990		begin
991			for i in str'range loop
992				Result(i)	:= chr_toUpper(str(i));
993			end loop;
994			return Result;
995		end function;
996	
997	end package body;
