202	package body vectors is
203		-- slicing boundary calulations
204		-- ==========================================================================
205		function low(lenvec : T_POSVEC; index : natural) return natural is
206			variable pos		: natural		:= 0;
207		begin
208			for i in lenvec'low to index - 1 loop
209				pos := pos + lenvec(i);
210			end loop;
211			return pos;
212		end function;
213	
214		function high(lenvec : T_POSVEC; index : natural) return natural is
215			variable pos		: natural		:= 0;
216		begin
217			for i in lenvec'low to index loop
218				pos := pos + lenvec(i);
219			end loop;
220			return pos - 1;
221		end function;
222	
223		-- Assign procedures: assign_*
224		-- ==========================================================================
225		procedure assign_row(signal slm : out T_SLM; slv : std_logic_vector; constant RowIndex : natural) is
226			variable temp : std_logic_vector(slm'high(2) downto slm'low(2));					-- WORKAROUND: Xilinx iSIM work-around, because 'range(2) evaluates to 'range(1); see work-around notes at T_SLM type declaration
227		begin
228			temp := slv;
229			for i in temp'range loop
230				slm(RowIndex, i)  <= temp(i);
231			end loop;
232		end procedure;
