234		procedure assign_row(signal slm : out T_SLM; slv : std_logic_vector; constant RowIndex : natural; Position : natural) is
235			variable temp : std_logic_vector(Position + slv'length - 1 downto Position);
236		begin
237			temp := slv;
238			for i in temp'range loop
239				slm(RowIndex, i)  <= temp(i);
240			end loop;
241		end procedure;
242	
243		procedure assign_row(signal slm : out T_SLM; slv : std_logic_vector; constant RowIndex : natural; High : natural; Low : natural) is
244			variable temp : std_logic_vector(High downto Low);
245		begin
246			temp := slv;
247			for i in temp'range loop
248				slm(RowIndex, i)  <= temp(i);
249			end loop;
250		end procedure;
251	
252		procedure assign_col(signal slm : out T_SLM; slv : std_logic_vector; constant ColIndex : natural) is
253			variable temp : std_logic_vector(slm'range(1));
254		begin
255			temp := slv;
256			for i in temp'range loop
257				slm(i, ColIndex)  <= temp(i);
258			end loop;
259		end procedure;
260	
261		-- Matrix to matrix conversion: slm_slice*
262		-- ==========================================================================
263		function slm_slice(slm : T_SLM; RowIndex : natural; ColIndex : natural; Height : natural; Width : natural) return T_SLM is
264			variable Result		: T_SLM(Height - 1 downto 0, Width - 1 downto 0)		:= (others => (others => '0'));
265		begin
266			for i in 0 to Height - 1 loop
267				for j in 0 to Width - 1 loop
268					Result(i, j)		:= slm(RowIndex + i, ColIndex + j);
269				end loop;
270			end loop;
271			return Result;
272		end function;
273	
274		function slm_slice_rows(slm : T_SLM; High : natural; Low : natural) return T_SLM is
275			variable Result		: T_SLM(High - Low downto 0, slm'length(2) - 1 downto 0)		:= (others => (others => '0'));
276		begin
277			for i in 0 to High - Low loop
278				for j in 0 to slm'length(2) - 1 loop
279					Result(i, j)		:= slm(Low + i, slm'low(2) + j);
280				end loop;
281			end loop;
282			return Result;
283		end function;
284	
285		function slm_slice_cols(slm : T_SLM; High : natural; Low : natural) return T_SLM is
286			variable Result		: T_SLM(slm'length(1) - 1 downto 0, High - Low downto 0)		:= (others => (others => '0'));
287		begin
288			for i in 0 to slm'length(1) - 1 loop
289				for j in 0 to High - Low loop
290					Result(i, j)		:= slm(slm'low(1) + i, Low + j);
291				end loop;
292			end loop;
293			return Result;
294		end function;
295	
296		-- Boolean Operators
297		function "not"(a : t_slm) return t_slm is
298			variable  res : t_slm(a'range(1), a'range(2));
299		begin
300			for i in res'range(1) loop
301				for j in res'range(2) loop
302					res(i, j) := not a(i, j);
303				end loop;
304			end loop;
305			return  res;
306		end function;
307	
308		function "and"(a, b : t_slm) return t_slm is
309			variable  bb, res : t_slm(a'range(1), a'range(2));
310		begin
311			bb := b;
312			for i in res'range(1) loop
313				for j in res'range(2) loop
314					res(i, j) := a(i, j) and bb(i, j);
315				end loop;
316			end loop;
317			return  res;
318		end function;
319	
320		function "or"(a, b : t_slm) return t_slm is
321			variable  bb, res : t_slm(a'range(1), a'range(2));
322		begin
323			bb := b;
324			for i in res'range(1) loop
325				for j in res'range(2) loop
326					res(i, j) := a(i, j) or bb(i, j);
327				end loop;
328			end loop;
329			return  res;
330		end function;
331	
332		function "xor"(a, b : t_slm) return t_slm is
333			variable  bb, res : t_slm(a'range(1), a'range(2));
334		begin
335			bb := b;
336			for i in res'range(1) loop
337				for j in res'range(2) loop
338					res(i, j) := a(i, j) xor bb(i, j);
339				end loop;
340			end loop;
341			return  res;
342		end function;
343	
344		function "nand"(a, b : t_slm) return t_slm is
345		begin
346			return  not(a and b);
347		end function;
348	
349	  function "nor"(a, b : t_slm) return t_slm is
