824		end function;
825	
826		function to_slm(slvv : T_SLVV_48) return T_SLM is
827			variable slm		: T_SLM(slvv'range, 47 downto 0);
828		begin
829			for i in slvv'range loop
830				for j in T_SLV_48'range loop
831					slm(i, j)		:= slvv(i)(j);
832				end loop;
833			end loop;
834			return slm;
835		end function;
836	
837		function to_slm(slvv : T_SLVV_64) return T_SLM is
838			variable slm		: T_SLM(slvv'range, 63 downto 0);
839		begin
840			for i in slvv'range loop
841				for j in T_SLV_64'range loop
842					slm(i, j)		:= slvv(i)(j);
843				end loop;
844			end loop;
845			return slm;
846		end function;
847	
848		function to_slm(slvv : T_SLVV_128) return T_SLM is
849			variable slm		: T_SLM(slvv'range, 127 downto 0);
850		begin
851			for i in slvv'range loop
852				for j in T_SLV_128'range loop
853					slm(i, j)		:= slvv(i)(j);
854				end loop;
855			end loop;
856			return slm;
857		end function;
858	
859		function to_slm(slvv : T_SLVV_256) return T_SLM is
860			variable slm		: T_SLM(slvv'range, 255 downto 0);
861		begin
862			for i in slvv'range loop
863				for j in T_SLV_256'range loop
864					slm(i, j)		:= slvv(i)(j);
865				end loop;
866			end loop;
867			return slm;
868		end function;
869	
870		function to_slm(slvv : T_SLVV_512) return T_SLM is
871			variable slm		: T_SLM(slvv'range, 511 downto 0);
872		begin
873			for i in slvv'range loop
874				for j in T_SLV_512'range loop
875					slm(i, j)		:= slvv(i)(j);
876				end loop;
877			end loop;
878			return slm;
879		end function;
880	
881		-- Change vector direction
882		-- ==========================================================================
883		function dir(slvv : T_SLVV_8) return T_SLVV_8 is
884			variable Result : T_SLVV_8(slvv'reverse_range);
885		begin
886			Result := slvv;
887			return Result;
888		end function;
889	
890		-- Reverse vector elements
891		function rev(slvv : T_SLVV_4) return T_SLVV_4 is
892			variable Result : T_SLVV_4(slvv'range);
893		begin
894			for i in slvv'low to slvv'high loop
895				Result(slvv'high - i) := slvv(i);
896			end loop;
897			return Result;
898		end function;
899	
900		function rev(slvv : T_SLVV_8) return T_SLVV_8 is
901			variable Result : T_SLVV_8(slvv'range);
902		begin
903			for i in slvv'low to slvv'high loop
904				Result(slvv'high - i) := slvv(i);
905			end loop;
906			return Result;
907		end function;
908	
909		function rev(slvv : T_SLVV_12) return T_SLVV_12 is
910			variable Result : T_SLVV_12(slvv'range);
911		begin
912			for i in slvv'low to slvv'high loop
913				Result(slvv'high - i) := slvv(i);
914			end loop;
915			return Result;
916		end function;
917	
918		function rev(slvv : T_SLVV_16) return T_SLVV_16 is
919			variable Result : T_SLVV_16(slvv'range);
920		begin
921			for i in slvv'low to slvv'high loop
922				Result(slvv'high - i) := slvv(i);
923			end loop;
924			return Result;
925		end function;
926	
927		function rev(slvv : T_SLVV_32) return T_SLVV_32 is
928			variable Result : T_SLVV_32(slvv'range);
929		begin
930			for i in slvv'low to slvv'high loop
931				Result(slvv'high - i) := slvv(i);
932			end loop;
933			return Result;
934		end function;
935	
936		function rev(slvv : T_SLVV_64) return T_SLVV_64 is
937			variable Result : T_SLVV_64(slvv'range);
938		begin
939			for i in slvv'low to slvv'high loop
940				Result(slvv'high - i) := slvv(i);
941			end loop;
942			return Result;
943		end function;
944	
945		function rev(slvv : T_SLVV_128) return T_SLVV_128 is
946			variable Result : T_SLVV_128(slvv'range);
947		begin
948			for i in slvv'low to slvv'high loop
949				Result(slvv'high - i) := slvv(i);
950			end loop;
951			return Result;
952		end function;
953	
954		function rev(slvv : T_SLVV_256) return T_SLVV_256 is
955			variable Result : T_SLVV_256(slvv'range);
956		begin
957			for i in slvv'low to slvv'high loop
958				Result(slvv'high - i) := slvv(i);
959			end loop;
960			return Result;
961		end function;
962	
963		function rev(slvv : T_SLVV_512) return T_SLVV_512 is
964			variable Result : T_SLVV_512(slvv'range);
965		begin
966			for i in slvv'low to slvv'high loop
967				Result(slvv'high - i) := slvv(i);
968			end loop;
969			return Result;
970		end function;
971	
972		-- Resize functions
973		-- ==========================================================================
974		-- Resizes the vector to the specified length. Input vectors larger than the specified size are truncated from the left side. Smaller input
975		-- vectors are extended on the left by the provided fill value (default: '0'). Use the resize functions of the numeric_std package for
976		-- value-preserving resizes of the signed and unsigned data types.
977		function resize(slm : T_SLM; size : positive) return T_SLM is
978			variable Result		: T_SLM(size - 1 downto 0, slm'high(2) downto slm'low(2))		:= (others => (others => '0'));					-- WORKAROUND: Xilinx iSIM work-around, because 'range(2) evaluates to 'range(1); see work-around notes at T_SLM type declaration
979		begin
980			for i in slm'range(1) loop
981				for j in slm'high(2) downto slm'low(2) loop					-- WORKAROUND: Xilinx iSIM work-around, because 'range(2) evaluates to 'range(1); see work-around notes at T_SLM type declaration
982					Result(i, j)	:= slm(i, j);
983				end loop;
984			end loop;
985			return Result;
986		end function;
987	
988		function to_string(slvv : T_SLVV_8; sep : character := ':') return string is
989			constant hex_len			: positive								:= ite((sep = C_POC_NUL), (slvv'length * 2), (slvv'length * 3) - 1);
990			variable Result				: string(1 to hex_len)		:= (others => sep);
991			variable pos					: positive								:= 1;
992		begin
993			for i in slvv'range loop
994				Result(pos to pos + 1)	:= to_string(slvv(i), 'h');
995				pos											:= pos + ite((sep = C_POC_NUL), 2, 3);
996			end loop;
997			return Result;
998		end function;
999	
1000		function to_string_bin(slm : T_SLM; groups : positive := 4; format : character := 'h') return string is
1001			variable PerLineOverheader	: positive	:= div_ceil(slm'length(2), groups);
1002			variable Result							: string(1 to (slm'length(1) * (slm'length(2) + PerLineOverheader)) + 10);
1003			variable Writer							: positive;
1004			variable GroupCounter				: natural;
1005		begin
1006			Result				:= (others => C_POC_NUL);
1007			Result(1)			:= LF;
1008			Writer				:= 2;
1009			GroupCounter	:= 0;
1010			for i in slm'low(1) to slm'high(1) loop
1011				for j in slm'high(2) downto slm'low(2) loop					-- WORKAROUND: Xilinx iSIM work-around, because 'range(2) evaluates to 'range(1); see work-around notes at T_SLM type declaration
1012					Result(Writer)		:= to_char(slm(i, j));
1013					Writer						:= Writer + 1;
1014					GroupCounter			:= GroupCounter + 1;
1015					if GroupCounter = groups then
1016						Result(Writer)	:= ' ';
1017						Writer					:= Writer + 1;
1018						GroupCounter		:= 0;
1019					end if;
1020				end loop;
1021				Result(Writer - 1)	:= LF;
1022				GroupCounter				:= 0;
1023			end loop;
1024			return str_trim(Result);
1025		end function;
1026	
1027		function to_string(slm : T_SLM; groups : positive := 4; format : character := 'b') return string is
1028		begin
1029			if (format = 'b') then
1030				return to_string_bin(slm, groups);
1031			else
1032				return "Format not supported.";
1033			end if;
1034		end function;
1035	end package body;
